import { Link } from 'react-router-dom';

const defaultPlans = [
  { name: 'Auto-entrepreneur', price: '600€ - 900€', period: '/an', description: 'Idéal pour les electriciens en statut auto-entrepreneur', features: ['Garantie Décennale', 'RC Pro incluse', 'Protection 10 ans', 'Sinistres couverts', 'Assistance juridique'], popular: false, badge: '', cta: 'Choisir cette formule' },
  { name: 'Artisan', price: '1000€ - 2000€', period: '/an', description: 'La formule la plus demandee par les artisans', features: ['Garantie Décennale', 'RC Pro incluse', 'Protection 10 ans', 'Sinistres couverts', 'Assistance juridique', 'Extension travaux', 'Gestion prioritaire'], popular: true, badge: 'Le plus populaire', cta: 'Choisir cette formule' },
  { name: 'Société', price: 'Sur devis', period: '', description: 'Pour les SARL, EURL et entreprises avec salaries', features: ['Garantie Décennale', 'RC Pro incluse', 'Protection 10 ans', 'Sinistres couverts', 'Assurance RC exploitation', 'Garantie bonne fin', 'Conseiller dédié'], popular: false, badge: '', cta: 'Contactez-nous' }
];

export default function Pricing({ section }) {
  const plans = section?.cards?.length > 0 
    ? section.cards.map(card => ({
        name: card.title,
        price: card.description || 'Sur devis',
        period: '',
        description: card.content || '',
        features: card.features || [],
        popular: card.isPopular || false,
        badge: card.badge || '',
        cta: 'Choisir cette formule'
      }))
    : defaultPlans;

  return (
    <section id="pricing" className="py-12 md:py-20 bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-10 md:mb-14">
          <h2 className="text-2xl sm:text-3xl md:text-4xl font-bold text-gray-900">
            {section?.title || 'Nos'} <span className="text-yellow-600">tarifs</span> transparents
          </h2>
          {section?.subtitle && (
            <p className="mt-3 sm:mt-4 text-gray-600 text-base md:text-lg max-w-2xl mx-auto">
              {section.subtitle}
            </p>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:gap-8 max-w-5xl mx-auto">
          {plans.map((plan, index) => (
            <div 
              key={index} 
              className={`bg-white rounded-2xl shadow-lg overflow-hidden ${
                plan.popular ? 'ring-2 sm:ring-4 ring-yellow-400 md:transform md:scale-105' : ''
              }`}
            >
              {(plan.popular || plan.badge) && (
                <div className="bg-yellow-500 text-center py-2 font-semibold text-sm text-white">
                  {plan.badge || 'Le plus populaire'}
                </div>
              )}
              <div className="p-6 sm:p-8">
                <h3 className="text-lg sm:text-xl font-bold text-gray-900">{plan.name}</h3>
                <div className="mt-3 sm:mt-4 flex items-baseline">
                  <span className="text-3xl sm:text-4xl font-bold text-yellow-600">{plan.price}</span>
                  <span className="text-gray-500 ml-1">{plan.period}</span>
                </div>
                <p className="mt-2 text-gray-500 text-sm">{plan.description}</p>

                <ul className="mt-5 sm:mt-6 space-y-2 sm:space-y-3">
                  {plan.features.map((feature, idx) => (
                    <li key={idx} className="flex items-center text-sm text-gray-600">
                      <span className="text-green-500 mr-2">✓</span>
                      {feature}
                    </li>
                  ))}
                </ul>

                <Link 
                  to="/#quote" 
                  className="mt-6 sm:mt-8 block w-full text-center py-3 rounded-xl font-semibold bg-yellow-500 text-white hover:bg-yellow-600"
                >
                  {plan.cta}
                </Link>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
